javascriptCopierModifierdocument.addEventListener("DOMContentLoaded", () => {
    const form = document.getElementById("addDataForm");

    // Populate the parent and dependents select fields
    async function fetchRelations() {
        try {
            const type = document.querySelector('input[name="type"]:checked').value;
            const parentResponse = await fetch(`/api/relations?type=${type}&relation=parent`);
            const dependentsResponse = await fetch(`/api/relations?type=${type}&relation=dependent`);
            const parents = await parentResponse.json();
            const dependents = await dependentsResponse.json();

            populateSelect("parent", parents.relations);
            populateSelect("dependents", dependents.relations);
        } catch (error) {
            console.error("Error fetching relations:", error);
        }
    }

    function populateSelect(selectId, data) {
        const select = document.getElementById(selectId);
        select.innerHTML = `<option value="">None</option>`;
        data.forEach(item => {
            select.innerHTML += `<option value="${item.id}">${item.name}</option>`;
        });
    }

    // Handle tag input
    const tagsInput = document.getElementById("tags");
    tagsInput.addEventListener("input", async () => {
        const query = tagsInput.value;
        try {
            const response = await fetch(`/api/tags?query=${query}`);
            const tags = await response.json();
            console.log("Suggested tags:", tags);
            // Add autocomplete logic here if needed
        } catch (error) {
            console.error("Error fetching tags:", error);
        }
    });

    // Handle form submission
    form.addEventListener("submit", async (event) => {
        event.preventDefault();

        // Collect form data
        const formData = new FormData(form);
        const data = {
            type: formData.get("type"),
            name: formData.get("name"),
            description: formData.get("description"),
            parent: formData.get("parent"),
            dependents: Array.from(formData.getAll("dependents")),
            tags: formData.get("tags").split(",").map(tag => tag.trim()),
            files: Array.from(document.getElementById("files").files).map(file => ({
                name: file.name,
                type: file.type,
                size: file.size
            }))
        };

        try {
            // Validate files
            for (const file of data.files) {
                const fileValidationResponse = await fetch("/api/validate_file", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({
                        file: btoa(file.name), // Encode file name for simplicity
                        allowed_types: ["pdf", "jpg", "png"],
                        max_size: 5000000
                    })
                });
                const validationResult = await fileValidationResponse.json();
                if (!validationResult.valid) {
                    alert(`File validation failed: ${validationResult.error}`);
                    return;
                }
            }

            // Submit form data to add data API
            const response = await fetch("/api/add_data", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(data)
            });
            const result = await response.json();

            if (result.success) {
                alert("Data added successfully!");
                form.reset();
            } else {
                alert(`Error adding data: ${result.error}`);
            }
        } catch (error) {
            console.error("Error submitting form:", error);
            alert("An error occurred. Please try again.");
        }
    });

    // Update relations on type change
    document.querySelectorAll('input[name="type"]').forEach(radio => {
        radio.addEventListener("change", fetchRelations);
    });

    // Initial fetch of relations
    fetchRelations();
});


Fonctionnalités du Script


Initialisation des relations :


Fait une requête API pour peupler les champs parent et dependents en fonction du type sélectionné (élément ou entité).




Autocomplétion des tags :


Récupère les suggestions dynamiquement en fonction de l'entrée dans le champ des tags.




Validation des fichiers :


Valide les fichiers uploadés avec l’API /api/validate_file pour vérifier leur type et leur taille.




Soumission du formulaire :


Formate les données saisies et les envoie à l’API /api/add_data.




Réactivité sur le type :


Met à jour les relations dynamiquement si le type (element ou entity) change.





